custom_css:
.letter-head {
	border-radius: 18px;
	padding: 8px 10px;
	margin: 10px 0 14px;
	font-family: Inter, sans-serif;
	font-size: 14px;
	color: #171717;
}

.letter-head td {
	padding: 0 !important;
	vertical-align: middle;
}

.invoice-header {
	width: 100%;
	border-collapse: collapse;
	table-layout: fixed;
	border-bottom: 1px solid #ededed;
	padding-bottom: 10px;
}

.logo-cell {
	width: 100px;
	text-align: center;
	white-space: nowrap;
}

.logo-container {
	display: inline-block;
	margin: auto;
}

.logo-container img {
	max-width: 95px;
	max-height: 95px;
	display: block;
	border-radius: 12px;
}

.company-details {
	width: 55%;
	padding-left: 10px !important;
	line-height: 1.5;
}

.company-name {
	font-size: 14px;
	font-weight: 600;
	color: #171717;
	margin-bottom: 4px;
}

.company-address {
	font-size: 14px;
	line-height: 1.5;
	color: #171717;
}

.invoice-info-cell {
	width: 240px;
	text-align: right;
	vertical-align: top !important;
	line-height: 1.5;
}

.document-name {
	font-size: 14px;
	font-weight: 600;
	color: #171717;
	margin-bottom: 6px;
}

.invoice-info {
	font-size: 14px;
	color: #171717;
	margin-bottom: 2px;
	font-variant-numeric: tabular-nums;
}

.invoice-label {
	color: #7c7c7c;
	font-weight: 500;
	margin-right: 4px;
	display: inline-block;
}
